const $=id=>document.getElementById(id);
let theme=localStorage.getItem("spanishwiseTheme")||"light";
let savedWords=JSON.parse(localStorage.getItem("spanishwiseSavedWords")||"[]");
let savedGrammar=JSON.parse(localStorage.getItem("spanishwiseSavedGrammar")||"[]");
let quizIndex=0,answered=false;
function applyTheme(next){theme=next==="dark"?"dark":"light";document.body.classList.toggle("dark",theme==="dark");$("themeToggle").textContent=theme==="dark"?"Light Mode":"Dark Mode";localStorage.setItem("spanishwiseTheme",theme)}
function setTab(tab){document.querySelectorAll(".tab-button").forEach(b=>b.classList.toggle("active",b.dataset.tab===tab));["today","words","grammar","quiz","saved"].forEach(n=>$(n+"Tab").hidden=n!==tab);if(tab==="saved")renderSaved()}
function todayWord(){const start=new Date(new Date().getFullYear(),0,0);return WORDS[Math.floor((Date.now()-start)/86400000)%WORDS.length]}
function isSavedWord(w){return savedWords.includes(w.word)}
function isSavedGrammar(g){return savedGrammar.includes(g.title)}
function toggleWord(word){savedWords=savedWords.includes(word)?savedWords.filter(w=>w!==word):[...savedWords,word];localStorage.setItem("spanishwiseSavedWords",JSON.stringify(savedWords));renderToday();renderWords();renderSaved()}
function toggleGrammar(title){savedGrammar=savedGrammar.includes(title)?savedGrammar.filter(t=>t!==title):[...savedGrammar,title];localStorage.setItem("spanishwiseSavedGrammar",JSON.stringify(savedGrammar));renderGrammar();renderSaved()}
function wordHTML(w,full=false){return `<div class="word-header"><div><div class="word-title">${w.word}</div><div class="meaning">${w.meaning}</div></div><div class="badges"><span class="badge">${w.level}</span><span class="badge">${w.category}</span></div></div><p class="definition">${w.definition}</p><div class="example">${w.example}</div><div class="collocations">${w.collocations.map(c=>`<span class="pill">${c}</span>`).join("")}</div>${full?`<p class="hook"><strong>Memory hook:</strong> ${w.hook}</p><p class="mini"><strong>Related:</strong> ${w.related.join(", ")}</p>`:""}<div class="actions"><button class="primary" data-word="${w.word}">${isSavedWord(w)?"Unsave":"Save word"}</button></div>`}
function renderToday(){const w=todayWord();$("todayCard").innerHTML=wordHTML(w,true);$("todayCard").querySelector("[data-word]").onclick=()=>toggleWord(w.word)}
function renderWordCategories(){const cats=["all",...new Set(WORDS.map(w=>w.category))];$("wordCategory").innerHTML=cats.map(c=>`<option value="${c}">${c==="all"?"All categories":c}</option>`).join("")}
function renderWords(){const q=$("wordSearch").value.toLowerCase(),cat=$("wordCategory").value,level=$("wordLevel").value;const list=WORDS.filter(w=>(cat==="all"||w.category===cat)&&(level==="all"||w.level===level)&&[w.word,w.meaning,w.definition,w.example,w.category].join(" ").toLowerCase().includes(q));$("wordGrid").innerHTML=list.map(w=>`<article class="word-card">${wordHTML(w,false)}</article>`).join("")||`<div class="empty">No words found.</div>`;document.querySelectorAll("[data-word]").forEach(b=>b.onclick=()=>toggleWord(b.dataset.word))}
function renderGrammarCategories(){const cats=["all",...new Set(GRAMMAR.map(g=>g.category))];$("grammarCategory").innerHTML=cats.map(c=>`<option value="${c}">${c==="all"?"All grammar categories":c}</option>`).join("")}
function grammarHTML(g){return `<strong>${g.title}</strong><span class="badge">${g.category}</span><p class="definition">${g.rule}</p><div class="grammar-examples">${g.examples.map(e=>`<div>${e}</div>`).join("")}</div><p class="mini"><strong>Common mistake:</strong> ${g.mistake}</p><p class="mini"><strong>Mini drill:</strong> ${g.drill}</p><div class="actions"><button class="primary" data-grammar="${g.title}">${isSavedGrammar(g)?"Unsave":"Save topic"}</button></div>`}
function renderGrammar(){const q=$("grammarSearch").value.toLowerCase(),cat=$("grammarCategory").value;const list=GRAMMAR.filter(g=>(cat==="all"||g.category===cat)&&[g.title,g.category,g.rule,g.examples.join(" ")].join(" ").toLowerCase().includes(q));$("grammarList").innerHTML=list.map(g=>`<article class="grammar-card">${grammarHTML(g)}</article>`).join("")||`<div class="empty">No grammar topics found.</div>`;document.querySelectorAll("[data-grammar]").forEach(b=>b.onclick=()=>toggleGrammar(b.dataset.grammar))}
function renderQuiz(){answered=false;const q=QUIZ[quizIndex%QUIZ.length];$("quizProgress").textContent=`Question ${quizIndex+1} / ${QUIZ.length}`;$("quizBox").innerHTML=`<div class="quiz-question">${q.q}</div><div class="quiz-options">${q.o.map(o=>`<button class="option-button" data-option="${o}">${o}</button>`).join("")}</div><div id="quizExplanation" class="explanation"></div><div class="actions"><button id="nextQuestion" class="primary" type="button">Next question</button></div>`;document.querySelectorAll("[data-option]").forEach(b=>b.onclick=()=>answerQuiz(b.dataset.option));$("nextQuestion").onclick=()=>{quizIndex=(quizIndex+1)%QUIZ.length;renderQuiz()}}
function answerQuiz(option){if(answered)return;answered=true;const q=QUIZ[quizIndex%QUIZ.length];document.querySelectorAll("[data-option]").forEach(b=>{if(b.dataset.option===q.a)b.classList.add("correct");else if(b.dataset.option===option)b.classList.add("wrong")});$("quizExplanation").textContent=q.e}
function renderSaved(){const sw=WORDS.filter(w=>savedWords.includes(w.word));const sg=GRAMMAR.filter(g=>savedGrammar.includes(g.title));$("savedWords").innerHTML=sw.map(w=>`<article class="word-card"><strong>${w.word}</strong><span>${w.meaning}</span><div class="actions"><button data-word="${w.word}">Unsave</button></div></article>`).join("")||`<div class="empty">No saved words yet.</div>`;$("savedGrammar").innerHTML=sg.map(g=>`<article class="grammar-card"><strong>${g.title}</strong><span>${g.category}</span><div class="actions"><button data-grammar="${g.title}">Unsave</button></div></article>`).join("")||`<div class="empty">No saved grammar yet.</div>`;document.querySelectorAll("[data-word]").forEach(b=>b.onclick=()=>toggleWord(b.dataset.word));document.querySelectorAll("[data-grammar]").forEach(b=>b.onclick=()=>toggleGrammar(b.dataset.grammar))}
$("themeToggle").onclick=()=>applyTheme(theme==="dark"?"light":"dark");
document.querySelectorAll(".tab-button").forEach(b=>b.onclick=()=>setTab(b.dataset.tab));
